                           <span className="font-bold text-base leading-tight truncate w-full">{student.name}</span>
                           <span className="text-xs text-gray-500">{`${student.grade}-${student.class} ${student.number}번`}</span>
                       </button>
                   ))}
               </div>
           </div>
       );
   }

    return (
