const JobManagementView: React.FC<{ allStudents: User[] }> = ({ allStudents }) => {
    const [jobs, setJobs] = useState<Job[]>([]);
    const [loading, setLoading] = useState(true);

    // Modals
    const [showAddModal, setShowAddModal] = useState(false);
    const [editingJob, setEditingJob] = useState<Job | null>(null); // For Edit Modal
    const [assigningJob, setAssigningJob] = useState<Job | null>(null); // For Assign Modal

    // Deletion
    const [deletingJobId, setDeletingJobId] = useState<string | null>(null);

    // Feedback
    const [messageModal, setMessageModal] = useState<{ isOpen: boolean, type: 'success' | 'error', message: string }>({ isOpen: false, type: 'success', message: '' });

    const fetchJobs = useCallback(async () => {
        setLoading(true);
        try {
            const data = await api.getJobs();
            setJobs(data);
        } catch (error) {
            console.error("Failed to fetch jobs", error);
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => { fetchJobs(); }, [fetchJobs]);

    const handlePaySalary = async (jobId: string, incentive: number) => {
        try {
            // 1. Update incentive first
            await api.updateJobIncentive(jobId, incentive);
            // 2. Pay salary (base + incentive is handled by backend logic or simply base + current stored incentive)
            const msg = await api.payJobSalary(jobId);
            setMessageModal({ isOpen: true, type: 'success', message: `인센티브 ${incentive}권을 포함하여 ${msg}` });
            fetchJobs(); // Refresh to ensure UI stays in sync
        } catch (err: any) {
            setMessageModal({ isOpen: true, type: 'error', message: err.message });
        }
    };

    const handleDeleteJob = async () => {
        if (!deletingJobId) return;
        try {
            const msg = await api.deleteJob(deletingJobId);
            setMessageModal({ isOpen: true, type: 'success', message: msg });
            setDeletingJobId(null);
            fetchJobs();
        } catch (err: any) {
            setMessageModal({ isOpen: true, type: 'error', message: err.message });
        }
    };

    return (
        <div className="h-full flex flex-col">
            <div className="flex justify-between items-center mb-4">
                <h2 className="text-2xl font-bold text-gray-800">1인 1역 관리</h2>
                <div className="flex gap-2">
                     <button onClick={async () => {
                        if(window.confirm('모든 직업의 월급을 일괄 지급하시겠습니까? (설정된 인센티브 포함)')) {
                            try {
                                const msg = await api.payAllSalaries();
                                setMessageModal({ isOpen: true, type: 'success', message: msg });
                            } catch(e: any) {
                                setMessageModal({ isOpen: true, type: 'error', message: e.message });
                            }
                        }
                    }} className="px-3 py-2 bg-green-600 text-white rounded-lg text-sm font-bold shadow hover:bg-green-700 transition-colors">
                        전체 월급 지급
                    </button>
                    <button onClick={() => setShowAddModal(true)} className="px-3 py-2 bg-[#2B548F] text-white rounded-lg text-sm font-bold shadow hover:bg-[#234576] transition-colors">
                        + 직업 추가
                    </button>
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 overflow-y-auto pb-4">
                {jobs.map(job => (
                    <JobCard 
                        key={job.id} 
                        job={job} 
                        onPay={handlePaySalary}
                        onDelete={(id) => setDeletingJobId(id)}
                        onEdit={(j) => setEditingJob(j)}
                        onAssign={(j) => setAssigningJob(j)}
                    />
                ))}
            </div>

            {/* Add Job Modal */}
            {showAddModal && <AddJobModal onClose={() => setShowAddModal(false)} onComplete={() => { setShowAddModal(false); fetchJobs(); }} />}

            {/* Edit Job Modal */}
            {editingJob && <EditJobModal job={editingJob} onClose={() => setEditingJob(null)} onComplete={() => { setEditingJob(null); fetchJobs(); }} />}

            {/* Assign Student Modal */}
            {assigningJob && (
                <AssignStudentModal 
                    job={assigningJob} 
                    allStudents={allStudents} 
                    onClose={() => setAssigningJob(null)} 
                    onComplete={() => { fetchJobs(); setAssigningJob(null); }} 
                />
            )}

            {/* Delete Confirmation Modal */}
            <ConfirmModal 
                isOpen={!!deletingJobId} 
                title="1인 1역 삭제" 
                message="해당 1인 1역을 삭제하시겠습니까? 이 작업은 되돌릴 수 없습니다." 
                onConfirm={handleDeleteJob} 
                onCancel={() => setDeletingJobId(null)}
                confirmText="삭제"
                isDangerous={true}
            />

            <MessageModal 
                isOpen={messageModal.isOpen} 
                type={messageModal.type} 
                message={messageModal.message} 
                onClose={() => setMessageModal({ ...messageModal, isOpen: false })} 
            />
        </div>
    );
};

