    useEffect(() => { fetchTaxes(); }, [fetchTaxes]);

    const handleDelete = async (id: string) => {
        if(!window.confirm('이 세금 항목을 삭제하시겠습니까?')) return;
        await api.deleteTax(id);
        fetchTaxes();
    };

    return (
