const StudentManagementView: React.FC<{ students: (User & { account: Account | null })[], refresh: () => void }> = ({ students, refresh }) => {
    const [showAddModal, setShowAddModal] = useState(false);
    const [selectedStudentQr, setSelectedStudentQr] = useState<User & { account: Account | null } | null>(null);
    const [deleteMode, setDeleteMode] = useState(false);
    const [selectedIds, setSelectedIds] = useState<string[]>([]);
    const [message, setMessage] = useState<{ type: 'success' | 'error', text: string } | null>(null);

    const handleDelete = async () => {
        if (!window.confirm(`${selectedIds.length}명의 학생을 삭제하시겠습니까?`)) return;
        try {
            const msg = await api.deleteStudents(selectedIds);
            setMessage({ type: 'success', text: msg });
            setSelectedIds([]);
            setDeleteMode(false);
            refresh();
        } catch (e: any) {
            setMessage({ type: 'error', text: e.message });
        }
    };

    return (
        <div className="h-full flex flex-col">
            <div className="flex justify-between items-center mb-4">
                <h2 className="text-2xl font-bold text-gray-800">학생 관리</h2>
                <div className="flex gap-2">
                    <button onClick={() => setShowAddModal(true)} className="px-3 py-2 bg-[#2B548F] text-white rounded-lg text-sm font-bold shadow hover:bg-[#234576]">
                        + 학생 추가
                    </button>
                    <button onClick={() => { setDeleteMode(!deleteMode); setSelectedIds([]); }} className={`px-3 py-2 border rounded-lg text-sm font-bold shadow ${deleteMode ? 'bg-gray-200' : 'bg-white hover:bg-gray-50'}`}>
                        {deleteMode ? '취소' : '삭제 모드'}
                    </button>
                    {deleteMode && selectedIds.length > 0 && (
                        <button onClick={handleDelete} className="px-3 py-2 bg-red-600 text-white rounded-lg text-sm font-bold shadow hover:bg-red-700">
                            삭제 ({selectedIds.length})
                        </button>
                    )}
                </div>
            </div>

            <div className="bg-white rounded-xl shadow-sm overflow-hidden flex-grow overflow-y-auto">
                <table className="w-full text-sm">
                    <thead className="bg-gray-50 sticky top-0">
                        <tr>
                            {deleteMode && <th className="p-3 w-10"></th>}
                            <th className="p-3 text-left">번호</th>
                            <th className="p-3 text-left">이름</th>
                            <th className="p-3 text-left">아이디(계좌)</th>
                            <th className="p-3 text-center">QR</th>
                        </tr>
                    </thead>
                    <tbody>
                        {students.map(s => (
                            <tr key={s.userId} className="border-t hover:bg-gray-50">
                                {deleteMode && (
                                    <td className="p-3 text-center">
                                        <input 
                                            type="checkbox" 
                                            checked={selectedIds.includes(s.userId)} 
                                            onChange={(e) => {
                                                if (e.target.checked) setSelectedIds([...selectedIds, s.userId]);
                                                else setSelectedIds(selectedIds.filter(id => id !== s.userId));
                                            }}
                                        />
                                    </td>
                                )}
                                <td className="p-3">{s.grade}-{s.class} {s.number}</td>
                                <td className="p-3 font-bold">{s.name}</td>
                                <td className="p-3 font-mono text-gray-500">{s.userId}</td>
                                <td className="p-3 text-center">
                                    <button onClick={() => setSelectedStudentQr(s)} className="text-gray-400 hover:text-indigo-600">
                                        <QrCodeIcon className="w-5 h-5" />
                                    </button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            {showAddModal && <AddStudentModal onClose={() => setShowAddModal(false)} onComplete={refresh} />}

            {selectedStudentQr && (
                <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4" onClick={() => setSelectedStudentQr(null)}>
                    <div className="bg-white p-8 rounded-xl flex flex-col items-center" onClick={e => e.stopPropagation()}>
                        <h3 className="text-xl font-bold mb-4">{selectedStudentQr.name} 학생 접속 QR</h3>
                        {selectedStudentQr.account?.qrToken ? (
                            <QRCodeSVG value={`${window.location.protocol}//${window.location.host}/login?token=${selectedStudentQr.account.qrToken}`} size={200} />
                        ) : (
                            <p>QR 토큰이 없습니다.</p>
                        )}
                        <p className="mt-4 text-sm text-gray-500">이 QR코드를 스캔하여 로그인할 수 있습니다.</p>
                        <button onClick={() => setSelectedStudentQr(null)} className="mt-6 px-6 py-2 bg-gray-200 rounded-lg font-bold">닫기</button>
                    </div>
                </div>
            )}

            <MessageModal isOpen={!!message} type={message?.type || 'success'} message={message?.text || ''} onClose={() => setMessage(null)} />
        </div>
    );
};

