                            const profitRate = buyVal > 0 ? (profit / buyVal) * 100 : 0;

                            return (
                                <div key={ms.stockId} onClick={() => ms.stock && handleStockClick(ms.stock)} className="bg-white p-4 rounded-xl shadow-sm cursor-pointer hover:bg-gray-50">
