            </div>

            {showAddModal && <AddStudentModal onClose={() => setShowAddModal(false)} onComplete={refresh} />}

            {/* Student Detail Modal */}
            {selectedDetailStudent && (
                <StudentDetailModal 
                    student={selectedDetailStudent} 
                    onClose={() => setSelectedDetailStudent(null)} 
                />
