                        {selectedStudentQr.account?.qrToken ? (
                            <div className="p-4 border-4 border-gray-100 rounded-xl bg-white mb-4">
                                <QRCodeSVG value={`${window.location.protocol}//${window.location.host}?token=${selectedStudentQr.account.qrToken}`} size={180} />
                            </div>
