        <div className="flex h-full bg-gray-100">
             {/* Desktop Sidebar */}
            <aside className="hidden md:flex flex-col w-64 bg-white border-r p-4 shadow-sm z-10">
                <div className="px-2 mb-8">
                    <h1 className="text-xl font-bold text-gray-800">교사 관리자</h1>
