    useEffect(() => {
        fetchData();
    }, [fetchData]);

    const renderContent = () => {
        switch (view) {
            case 'dashboard':
                return <DashboardView students={students} refresh={fetchData} />;
            case 'students':
                return <StudentManagementView students={students} refresh={fetchData} />;
            case 'jobs':
                return <JobManagementView refresh={fetchData} />;
