const addStudent = async (name: string, grade: number, classNum: number, number: number): Promise<void> => {
    // RPC 'add_student_and_account' is failing with RLS error (42501). 
    // Fallback to direct insertion which might be allowed or is the intended path.

    // 1. Insert User
    const { data: user, error: userError } = await supabase
        .from('users')
        .insert([{
            name,
            role: 'student',
            grade,
            class: classNum,
            number
        }])
        .select()
        .single();

    if (userError) {
        handleSupabaseError(userError, 'addStudent (User Insert)');
    }

    if (!user) throw new Error("Failed to create user record");

    // 2. Generate Account ID: 권쌤은행 0{Grade}0{Class}{Number}
    const pad = (n: number) => n.toString().padStart(2, '0');
    const accountId = `권쌤은행 ${pad(grade)}${pad(classNum)}${pad(number)}`;
    // Generate simple random token for QR
    const qrToken = Math.random().toString(36).substring(2) + Math.random().toString(36).substring(2);

    // 3. Insert Account
    const { error: accountError } = await supabase
        .from('accounts')
        .insert([{
            userId: user.userId,
            accountId,
            balance: 0,
            qrToken
        }]);

    if (accountError) {
        // Rollback user if account creation fails
        await supabase.from('users').delete().eq('userId', user.userId);
        handleSupabaseError(accountError, 'addStudent (Account Insert)');
    }
};

const deleteStudents = async (userIds: string[]): Promise<string> => {
    let successCount = 0;
    const errors: string[] = [];
    let lastErrorMsg = "";

    console.log("Deleting students:", userIds); // 디버깅용 로그

    for (const userId of userIds) {
        try {
            // Call the backend RPC function which has SECURITY DEFINER to bypass RLS
            const { error } = await supabase.rpc('delete_student', { p_user_id: userId });

            if (error) {
                console.error(`Supabase RPC Error for ${userId}:`, error);
                throw error;
            }
            successCount++;
        } catch (error: any) {
            console.error(`Failed to delete student ${userId}:`, error);
            lastErrorMsg = error.message || JSON.stringify(error);
            // 특정 에러 코드 처리 (42883: 함수 없음, 42501: 권한 없음)
            if (error.code === '42883') {
                lastErrorMsg = "백엔드에 'delete_student' 함수가 없습니다. SQL을 실행해주세요.";
            } else if (error.code === '42501') {
                lastErrorMsg = "삭제 권한이 없습니다. SQL에서 GRANT EXECUTE 명령어를 실행해주세요.";
            }
            errors.push(userId);
        }
    }

    if (successCount === 0 && errors.length > 0) {
        // Throw the specific error from the DB to help debugging
        throw new Error(`삭제 실패: ${lastErrorMsg}`);
    }

    let message = `${successCount}명의 학생을 삭제했습니다.`;
    if (errors.length > 0) {
        message += `\n삭제 실패 (ID): ${errors.join(', ')}`;
    }

    return message;
};

