    if (rcptError) throw new Error(rcptError.message);

    return taxes.map((tax: any) => ({
        id: tax.id,
        name: tax.name,
        amount: tax.amount,
        dueDate: tax.due_date,
        createdAt: tax.created_at,
        recipients: recipients
            .filter((r: any) => r.tax_id === tax.id)
            .map((r: any) => ({
                id: r.id,
                taxId: r.tax_id,
                studentUserId: r.student_user_id,
                isPaid: r.is_paid,
                paidAt: r.paid_at
