// --- Helpers ---
const getQrBaseUrl = () => {
    let url = window.location.href.split('?')[0].split('#')[0];
    // Fix for blob URLs in preview environments
    if (url.startsWith('blob:')) {
        url = url.replace(/^blob:/, '');
    }
    // Remove trailing slash if present to avoid double slashes with query
    return url.replace(/\/$/, '');
};

