    const [settleModal, setSettleModal] = useState<{ isOpen: boolean, fund: Fund | null }>({ isOpen: false, fund: null });

    const fetchFunds = useCallback(async () => {
        setLoading(true);
        try {
            const data = await api.getFunds();
            setFunds(data);
        } catch (error) {
            console.error("Failed to fetch funds", error);
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        fetchFunds();
