// --- Helpers ---
const getQrBaseUrl = () => {
    // 1. Blob URL 처리 (개발/프리뷰 환경)
    // blob:https://domain.com/uuid 형태의 URL에서 uuid 경로는 외부 접근이 불가능하므로 제거하고 Origin만 사용
    if (window.location.protocol === 'blob:') {
        return window.location.origin;
    }

    // 2. 일반 URL 처리
    // 현재 URL에서 쿼리 스트링(?)과 해시(#) 제거
    let url = window.location.href.split('?')[0].split('#')[0];

    // 3. Trailing slash 제거
    return url.replace(/\/$/, '');
};

