// --- Helpers ---
const getQrBaseUrl = () => {
    // window.location.href를 파싱하여 origin과 pathname을 조합합니다.
    // 쿼리 스트링(search)과 해시(hash)는 제거합니다.
    // 이를 통해 앱이 서브 디렉토리에 배포되어 있어도 올바른 경로를 유지합니다.
    try {
        const url = new URL(window.location.href);
        // blob 프로토콜일 경우 origin은 정상이지만 pathname이 내부 ID일 수 있음.
        // 하지만 blob 환경에서는 외부 접근이 근본적으로 불가하므로, 
        // 일반적인 배포 환경(http/https)을 기준으로 올바른 경로(origin + pathname)를 반환하는 것이 최선입니다.
        let baseUrl = `${url.origin}${url.pathname}`;
        if (baseUrl.startsWith('blob:')) {
            baseUrl = baseUrl.replace('blob:', '');
        }
        return baseUrl;
    } catch (e) {
        // Fallback for older browsers or edge cases
        return window.location.href.split('?')[0].split('#')[0];
    }
};

