const addStockProduct = async (name: string, price: number): Promise<string> => {
    // FIX: 기존 RPC(add_stock_product)가 users 테이블에 접근하여 RLS 오류 발생.
    // 대신 stock_products 테이블에 직접 INSERT하여 권한 문제를 우회합니다.
    // DB 설정(Default Value)이 완료되었으므로 ID는 자동으로 생성됩니다.
    const { error } = await supabase
        .from('stock_products')
        .insert({ name: name, currentPrice: price });

    handleSupabaseError(error, 'addStockProduct (Direct Insert)');
    return '새로운 주식 종목이 추가되었습니다.';
};

const updateStockPrice = async (stockId: string, newPrice: number): Promise<string> => {
    // FIX: RPC 대신 테이블 직접 업데이트로 변경하여 확실하게 동작하도록 수정
    const { error: updateError } = await supabase
        .from('stock_products')
        .update({ currentPrice: newPrice })
        .eq('id', stockId);

    if (updateError) handleSupabaseError(updateError, 'updateStockPrice (Table)');

    // 이력 추가 (이력이 실패해도 가격 변경은 유지)
    // DB 설정(Default Value)이 완료되었으므로 ID는 자동으로 생성됩니다.
    const { error: historyError } = await supabase
        .from('stock_price_history')
        .insert({ stockId: stockId, price: newPrice });

    if (historyError) console.error("History insert failed", historyError);

    return '가격이 변경되었습니다.';
};

